// Test that FindSentences panics when SentenceMap is missing an entry for a referenced sentence ID.
func TestFindSentencesMissingEntryPanics(t *testing.T) {
   // Prepare Rank with one word referencing sentence IDs 1 and 2, but only sentence 1 exists.
   ranking := NewRank()
   // Manually add a word with ID 0 and sentence IDs [1,2]
   ranking.Words[0] = &Word{
       ID:              0,
       Token:           "",
       Weight:          0.0,
       Qty:             0,
       SentenceIDs:     []int{1, 2},
       ConnectionLeft:  map[int]int{},
       ConnectionRight: map[int]int{},
   }
   // Only provide sentence_map entry for ID 1
   ranking.SentenceMap = map[int]string{1: "Sentence1"}
   // Expect panic due to missing entry for sentence ID 2
   assert.Panics(t, func() {
       _ = FindSentences(ranking, ByQty, 10)
   })
}

