In Go you could mirror the Rust error propagation by returning an error from TokenizeText, for example:

func TokenizeText(rawText string, rule Rule) (Text, error) {
    var text Text
    var i int
    slen := len(rawText)

    for j, chr := range rawText {
        j += len(string(chr))
        if rule.IsSentenceSeparator(chr) || j == slen {
            sentence := rawText[i:j]
            if len(sentence) > 0 {
                words, err := findWords(sentence, rule)
                if err != nil {
                    return Text{}, err
                }
                if err := text.Append(sentence, words); err != nil {
                    return Text{}, err
                }
            }
            i = j
        }
    }

    return text, nil
}

